UPDATE poems SET pinyin = 'xī rì wò chuò bù zú kuā， jīn cháo fàng dàng sī wú yá。 chūn fēng dé yì mǎ tí jí， yī rì kàn jǐn zhǎng ān huā。', translation = '这首《登科后》可以先抓住“昔日龌龊不足夸”和“一日看尽长安花”这样的画面来理解。诗里写到春天、喜悦、人生，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '孟郊是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《登科后》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、喜悦、人生”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“昔日龌龊不足夸”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、喜悦、人生”主题。', annotated_content_json = '[{"char": "昔", "pinyin": "xī", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "龌", "pinyin": "wò", "punct": false}, {"char": "龊", "pinyin": "chuò", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "足", "pinyin": "zú", "punct": false}, {"char": "夸", "pinyin": "kuā", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "今", "pinyin": "jīn", "punct": false}, {"char": "朝", "pinyin": "cháo", "punct": false}, {"char": "放", "pinyin": "fàng", "punct": false}, {"char": "荡", "pinyin": "dàng", "punct": false}, {"char": "思", "pinyin": "sī", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "涯", "pinyin": "yá", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "得", "pinyin": "dé", "punct": false}, {"char": "意", "pinyin": "yì", "punct": false}, {"char": "马", "pinyin": "mǎ", "punct": false}, {"char": "蹄", "pinyin": "tí", "punct": false}, {"char": "疾", "pinyin": "jí", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "安", "pinyin": "ān", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 101;
UPDATE poems SET pinyin = 'sān gèng dēng huǒ wǔ gèng jī， zhèng shì nán ér dú shū shí。 hēi fā bù zhī qín xué zǎo， bái shǒu fāng huǐ dú shū chí。', translation = '这首《劝学》可以先抓住“三更灯火五更鸡”和“白首方悔读书迟”这样的画面来理解。诗里写到勤学、惜时、成长，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '颜真卿是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《劝学》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“勤学、惜时、成长”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“三更灯火五更鸡”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“勤学、惜时、成长”主题。', annotated_content_json = '[{"char": "三", "pinyin": "sān", "punct": false}, {"char": "更", "pinyin": "gèng", "punct": false}, {"char": "灯", "pinyin": "dēng", "punct": false}, {"char": "火", "pinyin": "huǒ", "punct": false}, {"char": "五", "pinyin": "wǔ", "punct": false}, {"char": "更", "pinyin": "gèng", "punct": false}, {"char": "鸡", "pinyin": "jī", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "正", "pinyin": "zhèng", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "男", "pinyin": "nán", "punct": false}, {"char": "儿", "pinyin": "ér", "punct": false}, {"char": "读", "pinyin": "dú", "punct": false}, {"char": "书", "pinyin": "shū", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "黑", "pinyin": "hēi", "punct": false}, {"char": "发", "pinyin": "fā", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "勤", "pinyin": "qín", "punct": false}, {"char": "学", "pinyin": "xué", "punct": false}, {"char": "早", "pinyin": "zǎo", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "首", "pinyin": "shǒu", "punct": false}, {"char": "方", "pinyin": "fāng", "punct": false}, {"char": "悔", "pinyin": "huǐ", "punct": false}, {"char": "读", "pinyin": "dú", "punct": false}, {"char": "书", "pinyin": "shū", "punct": false}, {"char": "迟", "pinyin": "chí", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 102;
UPDATE poems SET pinyin = 'quàn jūn mò xī jīn lǚ yī， quàn jūn xī qǔ shǎo nián shí。 huā kāi kān zhé zhí xū zhé， mò dài wú huā kōng zhé zhī。', translation = '这首《金缕衣》可以先抓住“劝君莫惜金缕衣”和“莫待无花空折枝”这样的画面来理解。诗里写到惜时、成长、花，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜秋娘是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《金缕衣》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“惜时、成长、花”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“劝君莫惜金缕衣”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“惜时、成长、花”主题。', annotated_content_json = '[{"char": "劝", "pinyin": "quàn", "punct": false}, {"char": "君", "pinyin": "jūn", "punct": false}, {"char": "莫", "pinyin": "mò", "punct": false}, {"char": "惜", "pinyin": "xī", "punct": false}, {"char": "金", "pinyin": "jīn", "punct": false}, {"char": "缕", "pinyin": "lǚ", "punct": false}, {"char": "衣", "pinyin": "yī", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "劝", "pinyin": "quàn", "punct": false}, {"char": "君", "pinyin": "jūn", "punct": false}, {"char": "惜", "pinyin": "xī", "punct": false}, {"char": "取", "pinyin": "qǔ", "punct": false}, {"char": "少", "pinyin": "shǎo", "punct": false}, {"char": "年", "pinyin": "nián", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "开", "pinyin": "kāi", "punct": false}, {"char": "堪", "pinyin": "kān", "punct": false}, {"char": "折", "pinyin": "zhé", "punct": false}, {"char": "直", "pinyin": "zhí", "punct": false}, {"char": "须", "pinyin": "xū", "punct": false}, {"char": "折", "pinyin": "zhé", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "莫", "pinyin": "mò", "punct": false}, {"char": "待", "pinyin": "dài", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "空", "pinyin": "kōng", "punct": false}, {"char": "折", "pinyin": "zhé", "punct": false}, {