UPDATE poems SET pinyin = 'shí nián mó yī jiàn， shuāng rèn wèi céng shì。 jīn rì bǎ shì jūn， shuí yǒu bù píng shì。', translation = '这首《剑客》可以先抓住“十年磨一剑”和“谁有不平事”这样的画面来理解。诗里写到志向、侠义、品格，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '贾岛是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《剑客》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“志向、侠义、品格”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“十年磨一剑”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“志向、侠义、品格”主题。', annotated_content_json = '[{"char": "十", "pinyin": "shí", "punct": false}, {"char": "年", "pinyin": "nián", "punct": false}, {"char": "磨", "pinyin": "mó", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "剑", "pinyin": "jiàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "霜", "pinyin": "shuāng", "punct": false}, {"char": "刃", "pinyin": "rèn", "punct": false}, {"char": "未", "pinyin": "wèi", "punct": false}, {"char": "曾", "pinyin": "céng", "punct": false}, {"char": "试", "pinyin": "shì", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "今", "pinyin": "jīn", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "把", "pinyin": "bǎ", "punct": false}, {"char": "示", "pinyin": "shì", "punct": false}, {"char": "君", "pinyin": "jūn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "谁", "pinyin": "shuí", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "平", "pinyin": "píng", "punct": false}, {"char": "事", "pinyin": "shì", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 104;
UPDATE poems SET pinyin = 'liǎng jù sān nián dé， yī yín shuāng lèi liú。 zhī yīn rú bù shǎng， guī wò gù shān qiū。', translation = '这首《题诗后》可以先抓住“两句三年得”和“归卧故山秋”这样的画面来理解。诗里写到勤奋、写作、秋天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '贾岛是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《题诗后》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“勤奋、写作、秋天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“两句三年得”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“勤奋、写作、秋天”主题。', annotated_content_json = '[{"char": "两", "pinyin": "liǎng", "punct": false}, {"char": "句", "pinyin": "jù", "punct": false}, {"char": "三", "pinyin": "sān", "punct": false}, {"char": "年", "pinyin": "nián", "punct": false}, {"char": "得", "pinyin": "dé", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "吟", "pinyin": "yín", "punct": false}, {"char": "双", "pinyin": "shuāng", "punct": false}, {"char": "泪", "pinyin": "lèi", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "音", "pinyin": "yīn", "punct": false}, {"char": "如", "pinyin": "rú", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "赏", "pinyin": "shǎng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "卧", "pinyin": "wò", "punct": false}, {"char": "故", "pinyin": "gù", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 105;
UPDATE poems SET pinyin = 'bàn yè hū ér chèn xiǎo gēng， léi niú wú lì jiàn jiān xíng。 shí rén bù shí nóng jiā kǔ， jiāng wèi tián zhōng gǔ zì shēng。', translation = '这首《农家》可以先抓住“半夜呼儿趁晓耕”和“将谓田中谷自生”这样的画面来理解。诗里写到劳动、农事、节约，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '颜仁郁是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《农家》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“劳动、农事、节约”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“半夜呼儿趁晓耕”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“劳动、农事、节约”主题。', annotated_content_json = '[{"char": "半", "pinyin": "bàn", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "呼", "pinyin": "hū", "punct": false}, {"char": "儿", "pinyin": "ér", "punct": false}, {"char": "趁", "pinyin": "chèn", "punct": false}, {"char": "晓", "pinyin": "xiǎo", "punct": false}, {"char": "耕", "pinyin": "gēng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "羸", "pinyin": "léi", "punct": false}, {"char": "牛", "pinyin": "niú", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "力", "pinyin": "lì", "punct": false}, {"char": "渐", "pinyin": "jiàn", "punct": false}, {"char": "艰", "pinyin": "jiān", "punct": false}, {"char": "行", "pinyin": "xíng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "识", "pinyin": "shí", "punct": false}, {"char": "农", "pinyin": "nóng", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "苦", "pinyin": "kǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "将", "pinyin": "jiāng", "punct": false}, {"char": "谓", "pinyin": "wèi", "punct": false}, {"char": "田", "pinyin": "tián", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "谷", "pinyin": "gǔ", "punct": false}, {"char": "自", "pinyin": "zì", "