UPDATE poems SET pinyin = 'zuó rì rù chéng shì， guī lái lèi mǎn jīn。 biàn shēn luó qǐ zhě， bù shì yǎng cán rén。', translation = '这首《蚕妇》可以先抓住“昨日入城市”和“不是养蚕人”这样的画面来理解。诗里写到劳动、悲悯、生活，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '张俞是宋代诗人。这首诗篇幅不长，但画面感很强。孩子读《蚕妇》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“劳动、悲悯、生活”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“昨日入城市”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“劳动、悲悯、生活”主题。', annotated_content_json = '[{"char": "昨", "pinyin": "zuó", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "市", "pinyin": "shì", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "泪", "pinyin": "lèi", "punct": false}, {"char": "满", "pinyin": "mǎn", "punct": false}, {"char": "巾", "pinyin": "jīn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "遍", "pinyin": "biàn", "punct": false}, {"char": "身", "pinyin": "shēn", "punct": false}, {"char": "罗", "pinyin": "luó", "punct": false}, {"char": "绮", "pinyin": "qǐ", "punct": false}, {"char": "者", "pinyin": "zhě", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "养", "pinyin": "yǎng", "punct": false}, {"char": "蚕", "pinyin": "cán", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 107;
UPDATE poems SET pinyin = 'táo jǐn mén qián tǔ， wū shàng wú piàn wǎ。 shí zhǐ bù zhān ní， lín lín jū dà shà。', translation = '这首《陶者》可以先抓住“陶尽门前土”和“鳞鳞居大厦”这样的画面来理解。诗里写到劳动、悲悯、生活，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '梅尧臣是宋代诗人。这首诗篇幅不长，但画面感很强。孩子读《陶者》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“劳动、悲悯、生活”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“陶尽门前土”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“劳动、悲悯、生活”主题。', annotated_content_json = '[{"char": "陶", "pinyin": "táo", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "门", "pinyin": "mén", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "土", "pinyin": "tǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "屋", "pinyin": "wū", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "片", "pinyin": "piàn", "punct": false}, {"char": "瓦", "pinyin": "wǎ", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "十", "pinyin": "shí", "punct": false}, {"char": "指", "pinyin": "zhǐ", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "沾", "pinyin": "zhān", "punct": false}, {"char": "泥", "pinyin": "ní", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "鳞", "pinyin": "lín", "punct": false}, {"char": "鳞", "pinyin": "lín", "punct": false}, {"char": "居", "pinyin": "jū", "punct": false}, {"char": "大", "pinyin": "dà", "punct": false}, {"char": "厦", "pinyin": "shà", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 108;
UPDATE poems SET pinyin = 'lǜ biàn shān yuán bái mǎn chuān， zi guī shēng lǐ yǔ rú yān。 xiāng cūn sì yuè xián rén shǎo， cái le cán sāng yòu chā tián。', translation = '这首《乡村四月》可以先抓住“绿遍山原白满川”和“才了蚕桑又插田”这样的画面来理解。诗里写到乡村、劳动、春天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '翁卷是宋代诗人。这首诗篇幅不长，但画面感很强。孩子读《乡村四月》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“乡村、劳动、春天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“绿遍山原白满川”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“乡村、劳动、春天”主题。', annotated_content_json = '[{"char": "绿", "pinyin": "lǜ", "punct": false}, {"char": "遍", "pinyin": "biàn", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "原", "pinyin": "yuán", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "满", "pinyin": "mǎn", "punct": false}, {"char": "川", "pinyin": "chuān", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "子", "pinyin": "zi", "punct": false}, {"char": "规", "pinyin": "guī", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "如", "pinyin": "rú", "punct": false}, {"char": "烟", "pinyin": "yān", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "乡", "pinyin": "xiāng", "punct": false}, {"char": "村", "pinyin": "cūn", "punct": false}, {"char": "四", "pinyin": "sì", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "闲", "pinyin": "xián", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "少", "pinyin": "shǎo", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "才", "pinyin": "cái", "punct": false}, {"char": "了", "pinyin": "le", "punct": false}, {"char": "蚕", "pinyin": "cán", "punct": false}, {"char": "桑", "pinyin": "sāng", "punct": false}, {"char": "又", "pinyin": "yòu", "punct": false}, {"char": "插", "pinyin": "c