UPDATE poems SET pinyin = 'huáng méi shí jié jiā jiā yǔ， qīng cǎo chí táng chù chù wā。 yǒu yuē bù lái guò yè bàn， xián qiāo qí zi luò dēng huā。', translation = '这首《约客》可以先抓住“黄梅时节家家雨”和“闲敲棋子落灯花”这样的画面来理解。诗里写到夏天、雨、生活，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '赵师秀是宋代诗人。这首诗篇幅不长，但画面感很强。孩子读《约客》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“夏天、雨、生活”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“黄梅时节家家雨”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“夏天、雨、生活”主题。', annotated_content_json = '[{"char": "黄", "pinyin": "huáng", "punct": false}, {"char": "梅", "pinyin": "méi", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "节", "pinyin": "jié", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "池", "pinyin": "chí", "punct": false}, {"char": "塘", "pinyin": "táng", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "蛙", "pinyin": "wā", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "约", "pinyin": "yuē", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "过", "pinyin": "guò", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "闲", "pinyin": "xián", "punct": false}, {"char": "敲", "pinyin": "qiāo", "punct": false}, {"char": "棋", "pinyin": "qí", "punct": false}, {"char": "子", "pinyin": "zi", "punct": false}, {"char": "落", "pinyin": "luò", "punct": false}, {"char": "灯", "pinyin": "dēng", "punct": f