UPDATE poems SET pinyin = 'yín zhú qiū guāng lěng huà píng， qīng luó xiǎo shàn pū liú yíng。 tiān jiē yè sè liáng rú shuǐ， wò kàn qiān niú zhī nǚ xīng。', translation = '这首《秋夕》可以先抓住“银烛秋光冷画屏”和“卧看牵牛织女星”这样的画面来理解。诗里写到秋天、夜晚、星空，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜牧是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《秋夕》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、夜晚、星空”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“银烛秋光冷画屏”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、夜晚、星空”主题。', annotated_content_json = '[{"char": "银", "pinyin": "yín", "punct": false}, {"char": "烛", "pinyin": "zhú", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "光", "pinyin": "guāng", "punct": false}, {"char": "冷", "pinyin": "lěng", "punct": false}, {"char": "画", "pinyin": "huà", "punct": false}, {"char": "屏", "pinyin": "píng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "轻", "pinyin": "qīng", "punct": false}, {"char": "罗", "pinyin": "luó", "punct": false}, {"char": "小", "pinyin": "xiǎo", "punct": false}, {"char": "扇", "pinyin": "shàn", "punct": false}, {"char": "扑", "pinyin": "pū", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "萤", "pinyin": "yíng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "阶", "pinyin": "jiē", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "色", "pinyin": "sè", "punct": false}, {"char": "凉", "pinyin": "liáng", "punct": false}, {"char": "如", "pinyin": "rú", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "卧", "pinyin": "wò", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "牵", "pinyin": "qiān", "punct": false}, {"char": "牛", "pinyin": "niú", "punct": false}, {"char": "织", "pinyin": "zhī", "punct": false}, {"char": "女", "pinyin": "