UPDATE poems SET pinyin = 'zhé jǐ chén shā tiě wèi xiāo， zì jiāng mó xǐ rèn qián cháo。 dōng fēng bù yǔ zhōu láng biàn， tóng què chūn shēn suǒ èr qiáo。', translation = '这首《赤壁》可以先抓住“折戟沉沙铁未销”和“铜雀春深锁二乔”这样的画面来理解。诗里写到历史、战争、哲理，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜牧是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《赤壁》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“历史、战争、哲理”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“折戟沉沙铁未销”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“历史、战争、哲理”主题。', annotated_content_json = '[{"char": "折", "pinyin": "zhé", "punct": false}, {"char": "戟", "pinyin": "jǐ", "punct": false}, {"char": "沉", "pinyin": "chén", "punct": false}, {"char": "沙", "pinyin": "shā", "punct": false}, {"char": "铁", "pinyin": "tiě", "punct": false}, {"char": "未", "pinyin": "wèi", "punct": false}, {"char": "销", "pinyin": "xiāo", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "自", "pinyin": "zì", "punct": false}, {"char": "将", "pinyin": "jiāng", "punct": false}, {"char": "磨", "pinyin": "mó", "punct": false}, {"char": "洗", "pinyin": "xǐ", "punct": false}, {"char": "认", "pinyin": "rèn", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "朝", "pinyin": "cháo", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "东", "pinyin": "dōng", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "与", "pinyin": "yǔ", "punct": false}, {"char": "周", "pinyin": "zhōu", "punct": false}, {"char": "郎", "pinyin": "láng", "punct": false}, {"char": "便", "pinyin": "biàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "铜", "pinyin": "tóng", "punct": false}, {"char": "雀", "pinyin": "què", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "深", "pinyin": "shēn", "punct": false}, {"char": "锁", "pinyin": "suǒ", "punct": false}, {"char": "二", "pinyin": "