UPDATE poems SET pinyin = 'qīng shān yǐn yǐn shuǐ tiáo tiáo， qiū jǐn jiāng nán cǎo wèi diāo。 èr shí sì qiáo míng yuè yè， yù rén hé chù jiào chuī xiāo。', translation = '这首《寄扬州韩绰判官》可以先抓住“青山隐隐水迢迢”和“玉人何处教吹箫”这样的画面来理解。诗里写到秋天、月夜、江南，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜牧是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《寄扬州韩绰判官》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、月夜、江南”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“青山隐隐水迢迢”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、月夜、江南”主题。', annotated_content_json = '[{"char": "青", "pinyin": "qīng", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "隐", "pinyin": "yǐn", "punct": false}, {"char": "隐", "pinyin": "yǐn", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "迢", "pinyin": "tiáo", "punct": false}, {"char": "迢", "pinyin": "tiáo", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "南", "pinyin": "nán", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "未", "pinyin": "wèi", "punct": false}, {"char": "凋", "pinyin": "diāo", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "二", "pinyin": "èr", "punct": false}, {"char": "十", "pinyin": "shí", "punct": false}, {"char": "四", "pinyin": "sì", "punct": false}, {"char": "桥", "pinyin": "qiáo", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "玉", "pinyin": "yù", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "教", "pinyin": "jiào", "punct": false}, {"char": "吹", "pi