UPDATE poems SET pinyin = 'yún mǔ píng fēng zhú yǐng shēn， zhǎng hé jiàn luò xiǎo xīng chén。 cháng é yīng huǐ tōu líng yào， bì hǎi qīng tiān yè yè xīn。', translation = '这首《嫦娥》可以先抓住“云母屏风烛影深”和“碧海青天夜夜心”这样的画面来理解。诗里写到月夜、神话、想象，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李商隐是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《嫦娥》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“月夜、神话、想象”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“云母屏风烛影深”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“月夜、神话、想象”主题。', annotated_content_json = '[{"char": "云", "pinyin": "yún", "punct": false}, {"char": "母", "pinyin": "mǔ", "punct": false}, {"char": "屏", "pinyin": "píng", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "烛", "pinyin": "zhú", "punct": false}, {"char": "影", "pinyin": "yǐng", "punct": false}, {"char": "深", "pinyin": "shēn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "河", "pinyin": "hé", "punct": false}, {"char": "渐", "pinyin": "jiàn", "punct": false}, {"char": "落", "pinyin": "luò", "punct": false}, {"char": "晓", "pinyin": "xiǎo", "punct": false}, {"char": "星", "pinyin": "xīng", "punct": false}, {"char": "沉", "pinyin": "chén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "嫦", "pinyin": "cháng", "punct": false}, {"char": "娥", "pinyin": "é", "punct": false}, {"char": "应", "pinyin": "yīng", "punct": false}, {"char": "悔", "pinyin": "huǐ", "punct": false}, {"char": "偷", "pinyin": "tōu", "punct": false}, {"char": "灵", "pinyin": "líng", "punct": false}, {"char": "药", "pinyin": "yào", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "碧", "pinyin": "bì", "punct": false}, {"char": "海", "pinyin": "hǎi", "punct": false}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "夜", "pinyin