UPDATE poems SET pinyin = 'xiāng jiàn shí nán bié yì nán， dōng fēng wú lì bǎi huā cán。 chūn cán dào sǐ sī fāng jǐn， là jù chéng huī lèi shǐ gàn。', translation = '这首《无题》可以先抓住“相见时难别亦难”和“蜡炬成灰泪始干”这样的画面来理解。诗里写到离别、春天、情感，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李商隐是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《无题》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“离别、春天、情感”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“相见时难别亦难”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“离别、春天、情感”主题。', annotated_content_json = '[{"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "见", "pinyin": "jiàn", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "难", "pinyin": "nán", "punct": false}, {"char": "别", "pinyin": "bié", "punct": false}, {"char": "亦", "pinyin": "yì", "punct": false}, {"char": "难", "pinyin": "nán", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "东", "pinyin": "dōng", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "力", "pinyin": "lì", "punct": false}, {"char": "百", "pinyin": "bǎi", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "残", "pinyin": "cán", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "蚕", "pinyin": "cán", "punct": false}, {"char": "到", "pinyin": "dào", "punct": false}, {"char": "死", "pinyin": "sǐ", "punct": false}, {"char": "丝", "pinyin": "sī", "punct": false}, {"char": "方", "pinyin": "fāng", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "蜡", "pinyin": "là", "punct": false}, {"char": "炬", "pinyin": "jù", "punct": false}, {"char": "成", "pinyin": "chéng", "punct": false}, {"char": "灰", "pinyin": "huī", "punct": false}, {"char": "泪", "pinyin": "lèi", "punct": false}, {"char": "始", "pinyin": "shǐ", "punc