UPDATE poems SET pinyin = 'chū wén zhēng yàn yǐ wú chán， bǎi chǐ lóu gāo shuǐ jiē tiān。 qīng nǚ sù é jù nài lěng， yuè zhōng shuāng lǐ dòu chán juān。', translation = '这首《霜月》可以先抓住“初闻征雁已无蝉”和“月中霜里斗婵娟”这样的画面来理解。诗里写到秋天、月夜、想象，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李商隐是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《霜月》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、月夜、想象”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“初闻征雁已无蝉”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、月夜、想象”主题。', annotated_content_json = '[{"char": "初", "pinyin": "chū", "punct": false}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "征", "pinyin": "zhēng", "punct": false}, {"char": "雁", "pinyin": "yàn", "punct": false}, {"char": "已", "pinyin": "yǐ", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "蝉", "pinyin": "chán", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "百", "pinyin": "bǎi", "punct": false}, {"char": "尺", "pinyin": "chǐ", "punct": false}, {"char": "楼", "pinyin": "lóu", "punct": false}, {"char": "高", "pinyin": "gāo", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "接", "pinyin": "jiē", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "女", "pinyin": "nǚ", "punct": false}, {"char": "素", "pinyin": "sù", "punct": false}, {"char": "娥", "pinyin": "é", "punct": false}, {"char": "俱", "pinyin": "jù", "punct": false}, {"char": "耐", "pinyin": "nài", "punct": false}, {"char": "冷", "pinyin": "lěng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "霜", "pinyin": "shuāng", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "斗", "pinyin": "dòu", "punct": false}, {"char": "婵", "pinyin": "chán", "punct": false}, {"char": "娟", "pinyin": "juān", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 117;
UPDATE poems SET pinyin = 'xuān shì qiú xián fǎng zhú chén， jiǎ shēng cái diào gèng wú lún。 kě lián yè bàn xū qián xí， bù wèn cāng shēng wèn guǐ shén。', translation = '这首《贾生》可以先抓住“宣室求贤访逐臣”和“不问苍生问鬼神”这样的画面来理解。诗里写到历史、哲理、家国，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李商隐是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《贾生》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“历史、哲理、家国”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“宣室求贤访逐臣”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“历史、哲理、家国”主题。', annotated_content_json = '[{"char": "宣", "pinyin": "xuān", "punct": false}, {"char": "室", "pinyin": "shì", "punct": false}, {"char": "求", "pinyin": "qiú", "punct": false}, {"char": "贤", "pinyin": "xián", "punct": false}, {"char": "访", "pinyin": "fǎng", "punct": false}, {"char": "逐", "pinyin": "zhú", "punct": false}, {"char": "臣", "pinyin": "chén", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "贾", "pinyin": "jiǎ", "punct": false}, {"char": "生", "pinyin": "shēng", "punct": false}, {"char": "才", "pinyin": "cái", "punct": false}, {"char": "调", "pinyin": "diào", "punct": false}, {"char": "更", "pinyin": "gèng", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "伦", "pinyin": "lún", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "可", "pinyin": "kě", "punct": false}, {"char": "怜", "pinyin": "lián", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "虚", "pinyin": "xū", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "席", "pinyin": "xí", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "问", "pinyin": "wèn", "punct": false}, {"char": "苍", "pinyin": "cāng", "punct": false}, {"char": "生", "pinyin": "shēng", "punct": false}, {"char": "问", "pinyin": "wèn", "punct": false}, {"char": "鬼", "pinyin": "