UPDATE poems SET pinyin = 'rì mù cāng shān yuǎn， tiān hán bái wū pín。 chái mén wén quǎn fèi， fēng xuě yè guī rén。', translation = '这首《逢雪宿芙蓉山主人》可以先抓住“日暮苍山远”和“风雪夜归人”这样的画面来理解。诗里写到冬天、雪、山村，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '刘长卿是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《逢雪宿芙蓉山主人》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“冬天、雪、山村”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“日暮苍山远”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“冬天、雪、山村”主题。', annotated_content_json = '[{"char": "日", "pinyin": "rì", "punct": false}, {"char": "暮", "pinyin": "mù", "punct": false}, {"char": "苍", "pinyin": "cāng", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "远", "pinyin": "yuǎn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "寒", "pinyin": "hán", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "屋", "pinyin": "wū", "punct": false}, {"char": "贫", "pinyin": "pín", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "柴", "pinyin": "chái", "punct": false}, {"char": "门", "pinyin": "mén", "punct": false}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "犬", "pinyin": "quǎn", "punct": false}, {"char": "吠", "pinyin": "fèi", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "雪", "pinyin": "xuě", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 119;
UPDATE poems SET pinyin = 'cāng cāng zhú lín sì， yǎo yǎo zhōng shēng wǎn。 hé lì dài xié yáng， qīng shān dú guī yuǎn。', translation = '这首《送灵澈上人》可以先抓住“苍苍竹林寺”和“青山独归远”这样的画面来理解。诗里写到送别、山林、夕阳，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '刘长卿是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《送灵澈上人》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“送别、山林、夕阳”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“苍苍竹林寺”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“送别、山林、夕阳”主题。', annotated_content_json = '[{"char": "苍", "pinyin": "cāng", "punct": false}, {"char": "苍", "pinyin": "cāng", "punct": false}, {"char": "竹", "pinyin": "zhú", "punct": false}, {"char": "林", "pinyin": "lín", "punct": false}, {"char": "寺", "pinyin": "sì", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "杳", "pinyin": "yǎo", "punct": false}, {"char": "杳", "pinyin": "yǎo", "punct": false}, {"char": "钟", "pinyin": "zhōng", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "晚", "pinyin": "wǎn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "荷", "pinyin": "hé", "punct": false}, {"char": "笠", "pinyin": "lì", "punct": false}, {"char": "带", "pinyin": "dài", "punct": false}, {"char": "斜", "pinyin": "xié", "punct": false}, {"char": "阳", "pinyin": "yáng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "独", "pinyin": "dú", "punct": false}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "远", "pinyin": "yuǎn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 120;
UPDATE poems SET pinyin = 'gū yún jiāng yě hè， qǐ xiàng rén jiān zhù。 mò mǎi wò zhōu shān， shí rén yǐ zhī chù。', translation = '这首《送上人》可以先抓住“孤云将野鹤”和“时人已知处”这样的画面来理解。诗里写到送别、山林、隐逸，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '刘长卿是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《送上人》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“送别、山林、隐逸”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“孤云将野鹤”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“送别、山林、隐逸”主题。', annotated_content_json = '[{"char": "孤", "pinyin": "gū", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "将", "pinyin": "jiāng", "punct": false}, {"char": "野", "pinyin": "yě", "punct": false}, {"char": "鹤", "pinyin": "hè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "岂", "pinyin": "qǐ", "punct": false}, {"char": "向", "pinyin": "xiàng", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "间", "pinyin": "jiān", "punct": false}, {"char": "住", "pinyin": "zhù", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "莫", "pinyin": "mò", "punct": false}, {"char": "买", "pinyin": "mǎi", "punct": false}, {"char": "沃", "pinyin": "wò", "punct": false}, {"char": "洲", "pinyin": "zhōu", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "已", "pinyin": "yǐ", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 121;
UPDATE poems SET pinyin = 'lǐng wài yīn shū duàn， jīng dōng fù lì chūn。 jìn xiāng qíng gèng qiè， bù gǎn wèn lái rén。', translation = '这首《渡汉江》可以先抓住“岭外音书断”和“不敢问来人”这样的画面来理解。诗里写到思乡、春天、旅途，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '宋之问是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《渡汉江》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、春天、旅途”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“岭外音书断”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、春天、旅途”主题。', annotated_content_json = '[{"char": "岭", "pinyin": "lǐng", "punct": false}, {"char": "外", "pinyin": "wài", "punct": false}, {"char": "音", "pinyin": "yīn", "punct": false}, {"char": "书", "pinyin": "shū", "punct": false}, {"char": "断", "pinyin": "duàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "经", "pinyin": "jīng", "punct": false}, {"char": "冬", "pinyin": "dōng", "punct": false}, {"char": "复", "pinyin": "fù", "punct": false}, {"char": "历", "pinyin": "lì", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "近", "pinyin": "jìn", "punct": false}, {"char": "乡", "pinyin": "xiāng", "punct": false}, {"char": "情", "pinyin": "qíng", "punct": false}, {"char": "更", "pinyin": "gèng", "punct": false}, {"char": "怯", "pinyin": "qiè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "敢", "pinyin": "gǎn", "punct": false}, {"char": "问", "pinyin": "wèn", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 122;
UPDATE poems SET pinyin = 'jūn zì gù xiāng lái， yīng zhī gù xiāng shì。 lái rì qǐ chuāng qián， hán méi zhù huā wèi。', translation = '这首《杂诗》可以先抓住“君自故乡来”和“寒梅著花未”这样的画面来理解。诗里写到思乡、梅花、冬天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《杂诗》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、梅花、冬天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“君自故乡来”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、梅花、冬天”主题。', annotated_content_json = '[{"char": "君", "pinyin": "jūn", "punct": false}, {"char": "自", "pinyin": "zì", "punct": false}, {"char": "故", "pinyin": "gù", "punct": false}, {"char": "乡", "pinyin": "xiāng", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "应", "pinyin": "yīng", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "故", "pinyin": "gù", "punct": false}, {"char": "乡", "pinyin": "xiāng", "punct": false}, {"char": "事", "pinyin": "shì", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "绮", "pinyin": "qǐ", "punct": false}, {"char": "窗", "pinyin": "chuāng", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "寒", "pinyin": "hán", "punct": false}, {"char": "梅", "pinyin": "méi", "punct": false}, {"char": "著", "pinyin": "zhù", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "未", "pinyin": "wèi", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 123;
UPDATE poems SET pinyin = 'shān zhōng xiāng sòng bà， rì mù yǎn chái fēi。 chūn cǎo míng nián lǜ， wáng sūn guī bù guī。', translation = '这首《送别》可以先抓住“山中相送罢”和“王孙归不归”这样的画面来理解。诗里写到送别、春天、山林，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《送别》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“送别、春天、山林”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“山中相送罢”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“送别、春天、山林”主题。', annotated_content_json = '[{"char": "山", "pinyin": "shān", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "送", "pinyin": "sòng", "punct": false}, {"char": "罢", "pinyin": "bà", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "暮", "pinyin": "mù", "punct": false}, {"char": "掩", "pinyin": "yǎn", "punct": false}, {"char": "柴", "pinyin": "chái", "punct": false}, {"char": "扉", "pinyin": "fēi", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "年", "pinyin": "nián", "punct": false}, {"char": "绿", "pinyin": "lǜ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "王", "pinyin": "wáng", "punct": false}, {"char": "孙", "pinyin": "sūn", "punct": false}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 124;
UPDATE poems SET pinyin = 'dú zài yì xiāng wèi yì kè， měi féng jiā jié bèi sī qīn。 yáo zhī xiōng dì dēng gāo chù， biàn chā zhū yú shǎo yī rén。', translation = '这首《九月九日忆山东兄弟》可以先抓住“独在异乡为异客”和“遍插茱萸少一人”这样的画面来理解。诗里写到思乡、节日、亲情，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《九月九日忆山东兄弟》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、节日、亲情”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“独在异乡为异客”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、节日、亲情”主题。', annotated_content_json = '[{"char": "独", "pinyin": "dú", "punct": false}, {"char": "在", "pinyin": "zài", "punct": false}, {"char": "异", "pinyin": "yì", "punct": false}, {"char": "乡", "pinyin": "xiāng", "punct": false}, {"char": "为", "pinyin": "wèi", "punct": false}, {"char": "异", "pinyin": "yì", "punct": false}, {"char": "客", "pinyin": "kè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "每", "pinyin": "měi", "punct": false}, {"char": "逢", "pinyin": "féng", "punct": false}, {"char": "佳", "pinyin": "jiā", "punct": false}, {"char": "节", "pinyin": "jié", "punct": false}, {"char": "倍", "pinyin": "bèi", "punct": false}, {"char": "思", "pinyin": "sī", "punct": false}, {"char": "亲", "pinyin": "qīn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "遥", "pinyin": "yáo", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "兄", "pinyin": "xiōng", "punct": false}, {"char": "弟", "pinyin": "dì", "punct": false}, {"char": "登", "pinyin": "dēng", "punct": false}, {"char": "高", "pinyin": "gāo", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "遍", "pinyin": "biàn", "punct": false}, {"char": "插", "pinyin": "chā", "punct": false}, {"char": "茱", "pinyin": "zhū", "punct": false}, {"char": "萸", "pinyin": "yú", "punct": false}, {"char": "少", "pinyin": "shǎo", "punct": false}, {"char": "一", "pinyin": "y