UPDATE poems SET pinyin = 'rén xián guì huā luò， yè jìng chūn shān kōng。 yuè chū jīng shān niǎo， shí míng chūn jiàn zhōng。', translation = '这首《鸟鸣涧》可以先抓住“人闲桂花落”和“时鸣春涧中”这样的画面来理解。诗里写到春天、山水、月夜，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《鸟鸣涧》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、山水、月夜”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“人闲桂花落”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、山水、月夜”主题。', annotated_content_json = '[{"char": "人", "pinyin": "rén", "punct": false}, {"char": "闲", "pinyin": "xián", "punct": false}, {"char": "桂", "pinyin": "guì", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "落", "pinyin": "luò", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "静", "pinyin": "jìng", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "空", "pinyin": "kōng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "出", "pinyin": "chū", "punct": false}, {"char": "惊", "pinyin": "jīng", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "鸟", "pinyin": "niǎo", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "鸣", "pinyin": "míng", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "涧", "pinyin": "jiàn", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 126;
UPDATE poems SET pinyin = 'dú zuò yōu huáng lǐ， dàn qín fù zhǎng xiào。 shēn lín rén bù zhī， míng yuè lái xiāng zhào。', translation = '这首《竹里馆》可以先抓住“独坐幽篁里”和“明月来相照”这样的画面来理解。诗里写到月夜、山林、音乐，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《竹里馆》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“月夜、山林、音乐”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“独坐幽篁里”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“月夜、山林、音乐”主题。', annotated_content_json = '[{"char": "独", "pinyin": "dú", "punct": false}, {"char": "坐", "pinyin": "zuò", "punct": false}, {"char": "幽", "pinyin": "yōu", "punct": false}, {"char": "篁", "pinyin": "huáng", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "弹", "pinyin": "dàn", "punct": false}, {"char": "琴", "pinyin": "qín", "punct": false}, {"char": "复", "pinyin": "fù", "punct": false}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "啸", "pinyin": "xiào", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "深", "pinyin": "shēn", "punct": false}, {"char": "林", "pinyin": "lín", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "照", "pinyin": "zhào", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 127;
UPDATE poems SET pinyin = 'wèi chéng cháo yǔ yì qīng chén， kè shě qīng qīng liǔ sè xīn。 quàn jūn gèng jǐn yī bēi jiǔ， xī chū yáng guān wú gù rén。', translation = '这首《送元二使安西》可以先抓住“渭城朝雨浥轻尘”和“西出阳关无故人”这样的画面来理解。诗里写到送别、友情、春天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《送元二使安西》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“送别、友情、春天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“渭城朝雨浥轻尘”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“送别、友情、春天”主题。', annotated_content_json = '[{"char": "渭", "pinyin": "wèi", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "朝", "pinyin": "cháo", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "浥", "pinyin": "yì", "punct": false}, {"char": "轻", "pinyin": "qīng", "punct": false}, {"char": "尘", "pinyin": "chén", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "客", "pinyin": "kè", "punct": false}, {"char": "舍", "pinyin": "shě", "punct": false}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "柳", "pinyin": "liǔ", "punct": false}, {"char": "色", "pinyin": "sè", "punct": false}, {"char": "新", "pinyin": "xīn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "劝", "pinyin": "quàn", "punct": false}, {"char": "君", "pinyin": "jūn", "punct": false}, {"char": "更", "pinyin": "gèng", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "杯", "pinyin": "bēi", "punct": false}, {"char": "酒", "pinyin": "jiǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "西", "pinyin": "xī", "punct": false}, {"char": "出", "pinyin": "chū", "punct": false}, {"char": "阳", "pinyin": "yáng", "punct": false}, {"char": "关", "pinyin": "guān", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "故", "pinyin": "g