UPDATE poems SET pinyin = 'jīng xī bái shí chū， tiān hán hóng yè xī。 shān lù yuán wú yǔ， kōng cuì shī rén yī。', translation = '这首《山中》可以先抓住“荆溪白石出”和“空翠湿人衣”这样的画面来理解。诗里写到山水、秋天、冬天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《山中》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“山水、秋天、冬天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“荆溪白石出”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“山水、秋天、冬天”主题。', annotated_content_json = '[{"char": "荆", "pinyin": "jīng", "punct": false}, {"char": "溪", "pinyin": "xī", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "石", "pinyin": "shí", "punct": false}, {"char": "出", "pinyin": "chū", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "寒", "pinyin": "hán", "punct": false}, {"char": "红", "pinyin": "hóng", "punct": false}, {"char": "叶", "pinyin": "yè", "punct": false}, {"char": "稀", "pinyin": "xī", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "路", "pinyin": "lù", "punct": false}, {"char": "元", "pinyin": "yuán", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "空", "pinyin": "kōng", "punct": false}, {"char": "翠", "pinyin": "cuì", "punct": false}, {"char": "湿", "pinyin": "shī", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "衣", "pinyin": "yī", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 129;
UPDATE poems SET pinyin = 'yuǎn kàn shān yǒu sè， jìn tīng shuǐ wú shēng。 chūn qù huā hái zài， rén lái niǎo bù jīng。', translation = '这首《画》可以先抓住“远看山有色”和“人来鸟不惊”这样的画面来理解。诗里写到山水、儿童、春天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王维是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《画》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“山水、儿童、春天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“远看山有色”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“山水、儿童、春天”主题。', annotated_content_json = '[{"char": "远", "pinyin": "yuǎn", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "色", "pinyin": "sè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "近", "pinyin": "jìn", "punct": false}, {"char": "听", "pinyin": "tīng", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "去", "pinyin": "qù", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "还", "pinyin": "hái", "punct": false}, {"char": "在", "pinyin": "zài", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "鸟", "pinyin": "niǎo", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "惊", "pinyin": "jīng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 130;
UPDATE poems SET pinyin = 'zhòng niǎo gāo fēi jǐn， gū yún dú qù xián。 xiāng kàn liǎng bù yàn， zhǐ yǒu jìng tíng shān。', translation = '这首《独坐敬亭山》可以先抓住“众鸟高飞尽”和“只有敬亭山”这样的画面来理解。诗里写到山水、孤独、哲理，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《独坐敬亭山》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“山水、孤独、哲理”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“众鸟高飞尽”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“山水、孤独、哲理”主题。', annotated_content_json = '[{"char": "众", "pinyin": "zhòng", "punct": false}, {"char": "鸟", "pinyin": "niǎo", "punct": false}, {"char": "高", "pinyin": "gāo", "punct": false}, {"char": "飞", "pinyin": "fēi", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "孤", "pinyin": "gū", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "独", "pinyin": "dú", "punct": false}, {"char": "去", "pinyin": "qù", "punct": false}, {"char": "闲", "pinyin": "xián", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "两", "pinyin": "liǎng", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "厌", "pinyin": "yàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "只", "pinyin": "zhǐ", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "敬", "pinyin": "jìng", "punct": false}, {"char": "亭", "pinyin": "tíng", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 131;
UPDATE poems SET pinyin = 'bái fā sān qiān zhàng， yuán chóu shì gè zhǎng。 bù zhī míng jìng lǐ， hé chù dé qiū shuāng。', translation = '这首《秋浦歌》可以先抓住“白发三千丈”和“何处得秋霜”这样的画面来理解。诗里写到秋天、想象、人生，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《秋浦歌》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、想象、人生”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“白发三千丈”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、想象、人生”主题。', annotated_content_json = '[{"char": "白", "pinyin": "bái", "punct": false}, {"char": "发", "pinyin": "fā", "punct": false}, {"char": "三", "pinyin": "sān", "punct": false}, {"char": "千", "pinyin": "qiān", "punct": false}, {"char": "丈", "pinyin": "zhàng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "缘", "pinyin": "yuán", "punct": false}, {"char": "愁", "pinyin": "chóu", "punct": false}, {"char": "似", "pinyin": "shì", "punct": false}, {"char": "个", "pinyin": "gè", "punct": false}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "镜", "pinyin": "jìng", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "得", "pinyin": "dé", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "霜", "pinyin": "shuāng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 132;
UPDATE poems SET pinyin = 'wēi lóu gāo bǎi chǐ， shǒu kě zhāi xīng chén。 bù gǎn gāo shēng yǔ， kǒng jīng tiān shàng rén。', translation = '这首《夜宿山寺》可以先抓住“危楼高百尺”和“恐惊天上人”这样的画面来理解。诗里写到想象、星空、山寺，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《夜宿山寺》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“想象、星空、山寺”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“危楼高百尺”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“想象、星空、山寺”主题。', annotated_content_json = '[{"char": "危", "pinyin": "wēi", "punct": false}, {"char": "楼", "pinyin": "lóu", "punct": false}, {"char": "高", "pinyin": "gāo", "punct": false}, {"char": "百", "pinyin": "bǎi", "punct": false}, {"char": "尺", "pinyin": "chǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "手", "pinyin": "shǒu", "punct": false}, {"char": "可", "pinyin": "kě", "punct": false}, {"char": "摘", "pinyin": "zhāi", "punct": false}, {"char": "星", "pinyin": "xīng", "punct": false}, {"char": "辰", "pinyin": "chén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "敢", "pinyin": "gǎn", "punct": false}, {"char": "高", "pinyin": "gāo", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "语", "pinyin": "yǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "恐", "pinyin": "kǒng", "punct": false}, {"char": "惊", "pinyin": "jīng", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 133;
UPDATE poems SET pinyin = 'é méi shān yuè bàn lún qiū， yǐng rù píng qiāng jiāng shuǐ liú。 yè fā qīng xī xiàng sān xiá， sī jūn bù jiàn xià yú zhōu。', translation = '这首《峨眉山月歌》可以先抓住“峨眉山月半轮秋”和“思君不见下渝州”这样的画面来理解。诗里写到月夜、秋天、旅行，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《峨眉山月歌》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“月夜、秋天、旅行”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“峨眉山月半轮秋”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“月夜、秋天、旅行”主题。', annotated_content_json = '[{"char": "峨", "pinyin": "é", "punct": false}, {"char": "眉", "pinyin": "méi", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "轮", "pinyin": "lún", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "影", "pinyin": "yǐng", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "平", "pinyin": "píng", "punct": false}, {"char": "羌", "pinyin": "qiāng", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "发", "pinyin": "fā", "punct": false}, {"char": "清", "pinyin": "qīng", "punct": false}, {"char": "溪", "pinyin": "xī", "punct": false}, {"char": "向", "pinyin": "xiàng", "punct": false}, {"char": "三", "pinyin": "sān", "punct": false}, {"char": "峡", "pinyin": "xiá", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "思", "pinyin": "sī", "punct": false}, {"char": "君", "pinyin": "jūn", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "见", "pinyin": "jiàn", "punct": false}, {"char": "下", "pinyin": "xià", "punct": false}, {"char": "渝", "pinyin": "yú