UPDATE poems SET pinyin = 'wèn yú hé yì qī bì shān， xiào ér bù dá xīn zì xián。 táo huā liú shuǐ yǎo rán qù， bié yǒu tiān dì fēi rén jiān。', translation = '这首《山中问答》可以先抓住“问余何意栖碧山”和“别有天地非人间”这样的画面来理解。诗里写到山水、春天、闲适，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《山中问答》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“山水、春天、闲适”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“问余何意栖碧山”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“山水、春天、闲适”主题。', annotated_content_json = '[{"char": "问", "pinyin": "wèn", "punct": false}, {"char": "余", "pinyin": "yú", "punct": false}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "意", "pinyin": "yì", "punct": false}, {"char": "栖", "pinyin": "qī", "punct": false}, {"char": "碧", "pinyin": "bì", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "笑", "pinyin": "xiào", "punct": false}, {"char": "而", "pinyin": "ér", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "答", "pinyin": "dá", "punct": false}, {"char": "心", "pinyin": "xīn", "punct": false}, {"char": "自", "pinyin": "zì", "punct": false}, {"char": "闲", "pinyin": "xián", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "桃", "pinyin": "táo", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "窅", "pinyin": "yǎo", "punct": false}, {"char": "然", "pinyin": "rán", "punct": false}, {"char": "去", "pinyin": "qù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "别", "pinyin": "bié", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "地", "pinyin": "dì", "punct": false}, {"char": "非", "pinyin": "fēi", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "间", "pinyin": "jiān", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 135;
UPDATE poems SET pinyin = 'lán líng měi jiǔ yù jīn xiāng， yù wǎn shèng lái hǔ pò guāng。 dàn shǐ zhǔ rén néng zuì kè， bù zhī hé chù shì tā xiāng。', translation = '这首《客中行》可以先抓住“兰陵美酒郁金香”和“不知何处是他乡”这样的画面来理解。诗里写到友情、饮酒、旅行，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《客中行》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“友情、饮酒、旅行”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“兰陵美酒郁金香”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“友情、饮酒、旅行”主题。', annotated_content_json = '[{"char": "兰", "pinyin": "lán", "punct": false}, {"char": "陵", "pinyin": "líng", "punct": false}, {"char": "美", "pinyin": "měi", "punct": false}, {"char": "酒", "pinyin": "jiǔ", "punct": false}, {"char": "郁", "pinyin": "yù", "punct": false}, {"char": "金", "pinyin": "jīn", "punct": false}, {"char": "香", "pinyin": "xiāng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "玉", "pinyin": "yù", "punct": false}, {"char": "碗", "pinyin": "wǎn", "punct": false}, {"char": "盛", "pinyin": "shèng", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "琥", "pinyin": "hǔ", "punct": false}, {"char": "珀", "pinyin": "pò", "punct": false}, {"char": "光", "pinyin": "guāng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "但", "pinyin": "dàn", "punct": false}, {"char": "使", "pinyin": "shǐ", "punct": false}, {"char": "主", "pinyin": "zhǔ", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "能", "pinyin": "néng", "punct": false}, {"char": "醉", "pinyin": "zuì", "punct": false}, {"char": "客", "pinyin": "kè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "他", "pinyin": "tā", "punct