UPDATE poems SET pinyin = 'shuí jiā yù dí àn fēi shēng， sàn rù chūn fēng mǎn luò chéng。 cǐ yè qū zhōng wén zhé liǔ， hé rén bù qǐ gù yuán qíng。', translation = '这首《春夜洛城闻笛》可以先抓住“谁家玉笛暗飞声”和“何人不起故园情”这样的画面来理解。诗里写到思乡、春天、音乐，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '李白是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《春夜洛城闻笛》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、春天、音乐”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“谁家玉笛暗飞声”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、春天、音乐”主题。', annotated_content_json = '[{"char": "谁", "pinyin": "shuí", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "玉", "pinyin": "yù", "punct": false}, {"char": "笛", "pinyin": "dí", "punct": false}, {"char": "暗", "pinyin": "àn", "punct": false}, {"char": "飞", "pinyin": "fēi", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "散", "pinyin": "sàn", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "满", "pinyin": "mǎn", "punct": false}, {"char": "洛", "pinyin": "luò", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "此", "pinyin": "cǐ", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "曲", "pinyin": "qū", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "折", "pinyin": "zhé", "punct": false}, {"char": "柳", "pinyin": "liǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "起", "pinyin": "qǐ", "punct": false}, {"char": "故", "pinyin": "gù", "punct": false}, {"char": "园", "pinyin": "yuán", "punct": false}, {"char": "情", "pinyin": "qíng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 137;
UPDATE poems SET pinyin = 'gù yuán dōng wàng lù màn màn， shuāng xiù lóng zhōng lèi bù gàn。 mǎ shàng xiāng féng wú zhǐ bǐ， píng jūn chuán yǔ bào píng ān。', translation = '这首《逢入京使》可以先抓住“故园东望路漫漫”和“凭君传语报平安”这样的画面来理解。诗里写到思乡、边塞、亲情，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '岑参是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《逢入京使》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、边塞、亲情”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“故园东望路漫漫”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、边塞、亲情”主题。', annotated_content_json = '[{"char": "故", "pinyin": "gù", "punct": false}, {"char": "园", "pinyin": "yuán", "punct": false}, {"char": "东", "pinyin": "dōng", "punct": false}, {"char": "望", "pinyin": "wàng", "punct": false}, {"char": "路", "pinyin": "lù", "punct": false}, {"char": "漫", "pinyin": "màn", "punct": false}, {"char": "漫", "pinyin": "màn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "双", "pinyin": "shuāng", "punct": false}, {"char": "袖", "pinyin": "xiù", "punct": false}, {"char": "龙", "pinyin": "lóng", "punct": false}, {"char": "钟", "pinyin": "zhōng", "punct": false}, {"char": "泪", "pinyin": "lèi", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "干", "pinyin": "gàn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "马", "pinyin": "mǎ", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "逢", "pinyin": "féng", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "纸", "pinyin": "zhǐ", "punct": false}, {"char": "笔", "pinyin": "bǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "凭", "pinyin": "píng", "punct": false}, {"char": "君", "pinyin": "jūn", "punct": false}, {"char": "传", "pinyin": "chuán", "punct": false}, {"char": "语", "pinyin": "yǔ", "punct": false}, {"char": "报", "pinyin": "bào", "punct": false}, {"char": "平", "pi