UPDATE poems SET pinyin = 'běi fēng juǎn dì bái cǎo zhé， hú tiān bā yuè jí fēi xuě。 hū rú yī yè chūn fēng lái， qiān shù wàn shù lí huā kāi。', translation = '这首《白雪歌送武判官归京》可以先抓住“北风卷地白草折”和“千树万树梨花开”这样的画面来理解。诗里写到冬天、边塞、送别，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '岑参是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《白雪歌送武判官归京》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“冬天、边塞、送别”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“北风卷地白草折”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“冬天、边塞、送别”主题。', annotated_content_json = '[{"char": "北", "pinyin": "běi", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "卷", "pinyin": "juǎn", "punct": false}, {"char": "地", "pinyin": "dì", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "折", "pinyin": "zhé", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "胡", "pinyin": "hú", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "八", "pinyin": "bā", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "即", "pinyin": "jí", "punct": false}, {"char": "飞", "pinyin": "fēi", "punct": false}, {"char": "雪", "pinyin": "xuě", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "忽", "pinyin": "hū", "punct": false}, {"char": "如", "pinyin": "rú", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "千", "pinyin": "qiān", "punct": false}, {"char": "树", "pinyin": "shù", "punct": false}, {"char": "万", "pinyin": "wàn", "punct": false}, {"char": "树", "pinyin": "shù", "punct": false}, {"char": "梨", "pinyin": "lí", "punct": false}, {"char": "花", "pinyin": "huā", "p