UPDATE poems SET pinyin = 'qiān lǐ huáng yún bái rì xūn， běi fēng chuī yàn xuě fēn fēn。 mò chóu qián lù wú zhī jǐ， tiān xià shuí rén bù shí jūn。', translation = '这首《别董大》可以先抓住“千里黄云白日曛”和“天下谁人不识君”这样的画面来理解。诗里写到送别、友情、冬天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '高适是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《别董大》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“送别、友情、冬天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“千里黄云白日曛”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“送别、友情、冬天”主题。', annotated_content_json = '[{"char": "千", "pinyin": "qiān", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "黄", "pinyin": "huáng", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "曛", "pinyin": "xūn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "北", "pinyin": "běi", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "吹", "pinyin": "chuī", "punct": false}, {"char": "雁", "pinyin": "yàn", "punct": false}, {"char": "雪", "pinyin": "xuě", "punct": false}, {"char": "纷", "pinyin": "fēn", "punct": false}, {"char": "纷", "pinyin": "fēn", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "莫", "pinyin": "mò", "punct": false}, {"char": "愁", "pinyin": "chóu", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "路", "pinyin": "lù", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "己", "pinyin": "jǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "下", "pinyin": "xià", "punct": false}, {"char": "谁", "pinyin": "shuí", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "识", "pinyin": "shí", "pun