UPDATE poems SET pinyin = 'yuè hēi yàn fēi gāo， dān yú yè dùn táo。 yù jiāng qīng qí zhú， dà xuě mǎn gōng dāo。', translation = '这首《塞下曲》可以先抓住“月黑雁飞高”和“大雪满弓刀”这样的画面来理解。诗里写到边塞、战争、冬天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '卢纶是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《塞下曲》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“边塞、战争、冬天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“月黑雁飞高”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“边塞、战争、冬天”主题。', annotated_content_json = '[{"char": "月", "pinyin": "yuè", "punct": false}, {"char": "黑", "pinyin": "hēi", "punct": false}, {"char": "雁", "pinyin": "yàn", "punct": false}, {"char": "飞", "pinyin": "fēi", "punct": false}, {"char": "高", "pinyin": "gāo", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "单", "pinyin": "dān", "punct": false}, {"char": "于", "pinyin": "yú", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "遁", "pinyin": "dùn", "punct": false}, {"char": "逃", "pinyin": "táo", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "欲", "pinyin": "yù", "punct": false}, {"char": "将", "pinyin": "jiāng", "punct": false}, {"char": "轻", "pinyin": "qīng", "punct": false}, {"char": "骑", "pinyin": "qí", "punct": false}, {"char": "逐", "pinyin": "zhú", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "大", "pinyin": "dà", "punct": false}, {"char": "雪", "pinyin": "xuě", "punct": false}, {"char": "满", "pinyin": "mǎn", "punct": false}, {"char": "弓", "pinyin": "gōng", "punct": false}, {"char": "刀", "pinyin": "dāo", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 141;
UPDATE poems SET pinyin = 'lín àn cǎo jīng fēng， jiāng jūn yè yǐn gōng。 píng míng xún bái yǔ， méi zài shí léng zhōng。', translation = '这首《塞下曲其二》可以先抓住“林暗草惊风”和“没在石棱中”这样的画面来理解。诗里写到边塞、战争、勇敢，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '卢纶是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《塞下曲其二》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“边塞、战争、勇敢”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“林暗草惊风”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“边塞、战争、勇敢”主题。', annotated_content_json = '[{"char": "林", "pinyin": "lín", "punct": false}, {"char": "暗", "pinyin": "àn", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "惊", "pinyin": "jīng", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "将", "pinyin": "jiāng", "punct": false}, {"char": "军", "pinyin": "jūn", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "引", "pinyin": "yǐn", "punct": false}, {"char": "弓", "pinyin": "gōng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "平", "pinyin": "píng", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "寻", "pinyin": "xún", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "羽", "pinyin": "yǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "没", "pinyin": "méi", "punct": false}, {"char": "在", "pinyin": "zài", "punct": false}, {"char": "石", "pinyin": "shí", "punct": false}, {"char": "棱", "pinyin": "léng", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 142;
UPDATE poems SET pinyin = 'chūn chéng wú chù bù fēi huā， hán shí dōng fēng yù liǔ xié。 rì mù hàn gōng chuán là zhú， qīng yān sàn rù wǔ hóu jiā。', translation = '这首《寒食》可以先抓住“春城无处不飞花”和“轻烟散入五侯家”这样的画面来理解。诗里写到节日、春天、历史，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '韩翃是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《寒食》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“节日、春天、历史”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“春城无处不飞花”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“节日、春天、历史”主题。', annotated_content_json = '[{"char": "春", "pinyin": "chūn", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "飞", "pinyin": "fēi", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "寒", "pinyin": "hán", "punct": false}, {"char": "食", "pinyin": "shí", "punct": false}, {"char": "东", "pinyin": "dōng", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "御", "pinyin": "yù", "punct": false}, {"char": "柳", "pinyin": "liǔ", "punct": false}, {"char": "斜", "pinyin": "xié", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "暮", "pinyin": "mù", "punct": false}, {"char": "汉", "pinyin": "hàn", "punct": false}, {"char": "宫", "pinyin": "gōng", "punct": false}, {"char": "传", "pinyin": "chuán", "punct": false}, {"char": "蜡", "pinyin": "là", "punct": false}, {"char": "烛", "pinyin": "zhú", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "轻", "pinyin": "qīng", "punct": false}, {"char": "烟", "pinyin": "yān", "punct": false}, {"char": "散", "pinyin": "sàn", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "五", "pinyin": "wǔ", "punct": false}, {"char": "侯", "pinyin": "hóu", "punct":