UPDATE poems SET pinyin = 'dú lián yōu cǎo jiàn biān shēng， shàng yǒu huáng lí shēn shù míng。 chūn cháo dài yǔ wǎn lái jí， yě dù wú rén zhōu zì héng。', translation = '这首《滁州西涧》可以先抓住“独怜幽草涧边生”和“野渡无人舟自横”这样的画面来理解。诗里写到春天、山水、雨，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '韦应物是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《滁州西涧》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、山水、雨”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“独怜幽草涧边生”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、山水、雨”主题。', annotated_content_json = '[{"char": "独", "pinyin": "dú", "punct": false}, {"char": "怜", "pinyin": "lián", "punct": false}, {"char": "幽", "pinyin": "yōu", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "涧", "pinyin": "jiàn", "punct": false}, {"char": "边", "pinyin": "biān", "punct": false}, {"char": "生", "pinyin": "shēng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "黄", "pinyin": "huáng", "punct": false}, {"char": "鹂", "pinyin": "lí", "punct": false}, {"char": "深", "pinyin": "shēn", "punct": false}, {"char": "树", "pinyin": "shù", "punct": false}, {"char": "鸣", "pinyin": "míng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "潮", "pinyin": "cháo", "punct": false}, {"char": "带", "pinyin": "dài", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "晚", "pinyin": "wǎn", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "急", "pinyin": "jí", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "野", "pinyin": "yě", "punct": false}, {"char": "渡", "pinyin": "dù", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "舟", "pinyin": "zhōu", "punct": false}, {"char": "自", "pinyin": "