UPDATE poems SET pinyin = 'luò yáng chéng lǐ jiàn qiū fēng， yù zuò jiā shū yì wàn zhòng。 fù kǒng cōng cōng shuō bù jǐn， xíng rén lín fā yòu kāi fēng。', translation = '这首《秋思》可以先抓住“洛阳城里见秋风”和“行人临发又开封”这样的画面来理解。诗里写到思乡、秋天、亲情，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '张籍是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《秋思》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、秋天、亲情”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“洛阳城里见秋风”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、秋天、亲情”主题。', annotated_content_json = '[{"char": "洛", "pinyin": "luò", "punct": false}, {"char": "阳", "pinyin": "yáng", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "见", "pinyin": "jiàn", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "欲", "pinyin": "yù", "punct": false}, {"char": "作", "pinyin": "zuò", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "书", "pinyin": "shū", "punct": false}, {"char": "意", "pinyin": "yì", "punct": false}, {"char": "万", "pinyin": "wàn", "punct": false}, {"char": "重", "pinyin": "zhòng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "复", "pinyin": "fù", "punct": false}, {"char": "恐", "pinyin": "kǒng", "punct": false}, {"char": "匆", "pinyin": "cōng", "punct": false}, {"char": "匆", "pinyin": "cōng", "punct": false}, {"char": "说", "pinyin": "shuō", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "行", "pinyin": "xíng", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "临", "pinyin": "lín", "punct": false}, {"char": "发", "pinyin": "fā", "punct": false}, {"char": "又", "pinyin": "yòu", "punct": false}, {"char": "开", "pinyin": "kāi