UPDATE poems SET pinyin = 'zhōng tíng dì bái shù qī yā， lěng lù wú shēng shī guì huā。 jīn yè yuè míng rén jǐn wàng， bù zhī qiū sī luò shuí jiā。', translation = '这首《十五夜望月》可以先抓住“中庭地白树栖鸦”和“不知秋思落谁家”这样的画面来理解。诗里写到中秋、月夜、思乡，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王建是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《十五夜望月》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“中秋、月夜、思乡”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“中庭地白树栖鸦”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“中秋、月夜、思乡”主题。', annotated_content_json = '[{"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "庭", "pinyin": "tíng", "punct": false}, {"char": "地", "pinyin": "dì", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "树", "pinyin": "shù", "punct": false}, {"char": "栖", "pinyin": "qī", "punct": false}, {"char": "鸦", "pinyin": "yā", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "冷", "pinyin": "lěng", "punct": false}, {"char": "露", "pinyin": "lù", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "湿", "pinyin": "shī", "punct": false}, {"char": "桂", "pinyin": "guì", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "今", "pinyin": "jīn", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "望", "pinyin": "wàng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "思", "pinyin": "sī", "punct": false}, {"char": "落", "pinyin": "luò", "punct": false}, {"char": "谁", "pinyin": "shuí", "p