UPDATE poems SET pinyin = 'yǔ lǐ jī míng yī liǎng jiā， zhú xī cūn lù bǎn qiáo xié。 fù gū xiāng huàn yù cán qù， xián kàn zhōng tíng zhī zi huā。', translation = '这首《雨过山村》可以先抓住“雨里鸡鸣一两家”和“闲看中庭栀子花”这样的画面来理解。诗里写到乡村、雨、劳动，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王建是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《雨过山村》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“乡村、雨、劳动”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“雨里鸡鸣一两家”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“乡村、雨、劳动”主题。', annotated_content_json = '[{"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "鸡", "pinyin": "jī", "punct": false}, {"char": "鸣", "pinyin": "míng", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "两", "pinyin": "liǎng", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "竹", "pinyin": "zhú", "punct": false}, {"char": "溪", "pinyin": "xī", "punct": false}, {"char": "村", "pinyin": "cūn", "punct": false}, {"char": "路", "pinyin": "lù", "punct": false}, {"char": "板", "pinyin": "bǎn", "punct": false}, {"char": "桥", "pinyin": "qiáo", "punct": false}, {"char": "斜", "pinyin": "xié", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "妇", "pinyin": "fù", "punct": false}, {"char": "姑", "pinyin": "gū", "punct": false}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "唤", "pinyin": "huàn", "punct": false}, {"char": "浴", "pinyin": "yù", "punct": false}, {"char": "蚕", "pinyin": "cán", "punct": false}, {"char": "去", "pinyin": "qù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "闲", "pinyin": "xián", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "庭", "pinyin": "tíng", "punct": false}, {"char": "栀", "pinyin": "zhī", "punct": false}, {"char": "子", "pinyin": "zi", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 147;
UPDATE poems SET pinyin = 'sān rì rù chú xià， xǐ shǒu zuò gēng tāng。 wèi ān gū shí xìng， xiān qiǎn xiǎo gū cháng。', translation = '这首《新嫁娘词》可以先抓住“三日入厨下”和“先遣小姑尝”这样的画面来理解。诗里写到生活、家庭、习俗，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王建是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《新嫁娘词》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“生活、家庭、习俗”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“三日入厨下”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“生活、家庭、习俗”主题。', annotated_content_json = '[{"char": "三", "pinyin": "sān", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "厨", "pinyin": "chú", "punct": false}, {"char": "下", "pinyin": "xià", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "洗", "pinyin": "xǐ", "punct": false}, {"char": "手", "pinyin": "shǒu", "punct": false}, {"char": "作", "pinyin": "zuò", "punct": false}, {"char": "羹", "pinyin": "gēng", "punct": false}, {"char": "汤", "pinyin": "tāng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "未", "pinyin": "wèi", "punct": false}, {"char": "谙", "pinyin": "ān", "punct": false}, {"char": "姑", "pinyin": "gū", "punct": false}, {"char": "食", "pinyin": "shí", "punct": false}, {"char": "性", "pinyin": "xìng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "先", "pinyin": "xiān", "punct": false}, {"char": "遣", "pinyin": "qiǎn", "punct": false}, {"char": "小", "pinyin": "xiǎo", "punct": false}, {"char": "姑", "pinyin": "gū", "punct": false}, {"char": "尝", "pinyin": "cháng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 148;
UPDATE poems SET pinyin = 'xián jū shǎo lín bìng， cǎo jìng rù huāng yuán。 niǎo sù chí biān shù， sēng qiāo yuè xià mén。', translation = '这首《题李凝幽居》可以先抓住“闲居少邻并”和“僧敲月下门”这样的画面来理解。诗里写到月夜、山林、写作，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '贾岛是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《题李凝幽居》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“月夜、山林、写作”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“闲居少邻并”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“月夜、山林、写作”主题。', annotated_content_json = '[{"char": "闲", "pinyin": "xián", "punct": false}, {"char": "居", "pinyin": "jū", "punct": false}, {"char": "少", "pinyin": "shǎo", "punct": false}, {"char": "邻", "pinyin": "lín", "punct": false}, {"char": "并", "pinyin": "bìng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "径", "pinyin": "jìng", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "荒", "pinyin": "huāng", "punct": false}, {"char": "园", "pinyin": "yuán", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "鸟", "pinyin": "niǎo", "punct": false}, {"char": "宿", "pinyin": "sù", "punct": false}, {"char": "池", "pinyin": "chí", "punct": false}, {"char": "边", "pinyin": "biān", "punct": false}, {"char": "树", "pinyin": "shù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "僧", "pinyin": "sēng", "punct": false}, {"char": "敲", "pinyin": "qiāo", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "下", "pinyin": "xià", "punct": false}, {"char": "门", "pinyin": "mén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 149;
UPDATE poems SET pinyin = 'guī zhōng shǎo fù bù zhī chóu， chūn rì níng zhuāng shàng cuì lóu。 hū jiàn mò tóu yáng liǔ sè， huǐ jiào fū xù mì fēng hóu。', translation = '这首《闺怨》可以先抓住“闺中少妇不知愁”和“悔教夫婿觅封侯”这样的画面来理解。诗里写到春天、思念、边塞，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王昌龄是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《闺怨》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、思念、边塞”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“闺中少妇不知愁”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、思念、边塞”主题。', annotated_content_json = '[{"char": "闺", "pinyin": "guī", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "少", "pinyin": "shǎo", "punct": false}, {"char": "妇", "pinyin": "fù", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "愁", "pinyin": "chóu", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "凝", "pinyin": "níng", "punct": false}, {"char": "妆", "pinyin": "zhuāng", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "翠", "pinyin": "cuì", "punct": false}, {"char": "楼", "pinyin": "lóu", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "忽", "pinyin": "hū", "punct": false}, {"char": "见", "pinyin": "jiàn", "punct": false}, {"char": "陌", "pinyin": "mò", "punct": false}, {"char": "头", "pinyin": "tóu", "punct": false}, {"char": "杨", "pinyin": "yáng", "punct": false}, {"char": "柳", "pinyin": "liǔ", "punct": false}, {"char": "色", "pinyin": "sè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "悔", "pinyin": "huǐ", "punct": false}, {"char": "教", "pinyin": "jiào", "punct": false}, {"char": "夫", "pinyin": "fū", "punct": false}, {"char": "婿", "pinyin": "xù", "punct": false}, {"char": "觅", "pinyin": "mì", "punct": false}, {"char": "封", "pinyin": "fēng", "punct": false}, {"char": "侯", "pinyin": "hóu", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 150;
UPDATE poems SET pinyin = 'hán yǔ lián jiāng yè rù wú， píng míng sòng kè chǔ shān gū。 luò yáng qīn yǒu rú xiāng wèn， yī piàn bīng xīn zài yù hú。', translation = '这首《芙蓉楼送辛渐》可以先抓住“寒雨连江夜入吴”和“一片冰心在玉壶”这样的画面来理解。诗里写到送别、友情、品格，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王昌龄是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《芙蓉楼送辛渐》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“送别、友情、品格”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“寒雨连江夜入吴”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“送别、友情、品格”主题。', annotated_content_json = '[{"char": "寒", "pinyin": "hán", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "连", "pinyin": "lián", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "吴", "pinyin": "wú", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "平", "pinyin": "píng", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "送", "pinyin": "sòng", "punct": false}, {"char": "客", "pinyin": "kè", "punct": false}, {"char": "楚", "pinyin": "chǔ", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "孤", "pinyin": "gū", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "洛", "pinyin": "luò", "punct": false}, {"char": "阳", "pinyin": "yáng", "punct": false}, {"char": "亲", "pinyin": "qīn", "punct": false}, {"char": "友", "pinyin": "yǒu", "punct": false}, {"char": "如", "pinyin": "rú", "punct": false}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "问", "pinyin": "wèn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "片", "pinyin": "piàn", "punct": false}, {"char": "冰", "pinyin": "bīng", "punct": false}, {"char": "心", "pinyin": "xīn", "punct": false}, {"char": "在", "pinyin": "zài", "punct": false}, {"char": "玉", "pinyin": "yù", "punct": false}, {"char": "壶", "pinyin": "hú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 151;
UPDATE poems SET pinyin = 'hé yè luó qún yī sè cái， fú róng xiàng liǎn liǎng biān kāi。 luàn rù chí zhōng kàn bù jiàn， wén gē shǐ jué yǒu rén lái。', translation = '这首《采莲曲》可以先抓住“荷叶罗裙一色裁”和“闻歌始觉有人来”这样的画面来理解。诗里写到夏天、荷花、生活，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王昌龄是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《采莲曲》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“夏天、荷花、生活”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“荷叶罗裙一色裁”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“夏天、荷花、生活”主题。', annotated_content_json = '[{"char": "荷", "pinyin": "hé", "punct": false}, {"char": "叶", "pinyin": "yè", "punct": false}, {"char": "罗", "pinyin": "luó", "punct": false}, {"char": "裙", "pinyin": "qún", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "色", "pinyin": "sè", "punct": false}, {"char": "裁", "pinyin": "cái", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "芙", "pinyin": "fú", "punct": false}, {"char": "蓉", "pinyin": "róng", "punct": false}, {"char": "向", "pinyin": "xiàng", "punct": false}, {"char": "脸", "pinyin": "liǎn", "punct": false}, {"char": "两", "pinyin": "liǎng", "punct": false}, {"char": "边", "pinyin": "biān", "punct": false}, {"char": "开", "pinyin": "kāi", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "乱", "pinyin": "luàn", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "池", "pinyin": "chí", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "见", "pinyin": "jiàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "歌", "pinyin": "gē", "punct": false}, {"char": "始", "pinyin": "shǐ", "punct": false}, {"char": "觉", "pinyin": "jué", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 152;
UPDATE poems SET pinyin = 'huáng hé yuǎn shàng bái yún jiān， yī piàn gū chéng wàn rèn shān。 qiāng dí hé xū yuàn yáng liǔ， chūn fēng bù dù yù mén guān。', translation = '这首《凉州词》可以先抓住“黄河远上白云间”和“春风不度玉门关”这样的画面来理解。诗里写到边塞、黄河、春天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '王之涣是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《凉州词》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“边塞、黄河、春天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“黄河远上白云间”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“边塞、黄河、春天”主题。', annotated_content_json = '[{"char": "黄", "pinyin": "huáng", "punct": false}, {"char": "河", "pinyin": "hé", "punct": false}, {"char": "远", "pinyin": "yuǎn", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "间", "pinyin": "jiān", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "片", "pinyin": "piàn", "punct": false}, {"char": "孤", "pinyin": "gū", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "万", "pinyin": "wàn", "punct": false}, {"char": "仞", "pinyin": "rèn", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "羌", "pinyin": "qiāng", "punct": false}, {"char": "笛", "pinyin": "dí", "punct": false}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "须", "pinyin": "xū", "punct": false}, {"char": "怨", "pinyin": "yuàn", "punct": false}, {"char": "杨", "pinyin": "yáng", "punct": false}, {"char": "柳", "pinyin": "liǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "度", "pinyin": "dù", "punct": false}, {"char": "玉", "pinyin": "yù", "punct": false}, {"char": "门", "pinyin":