UPDATE poems SET pinyin = 'xī sāi shān qián bái lù fēi， táo huā liú shuǐ guì yú féi。 qīng ruò lì， lǜ suō yī， xié fēng xì yǔ bù xū guī。', translation = '这首《渔歌子》可以先抓住“西塞山前白鹭飞”和“斜风细雨不须归”这样的画面来理解。诗里写到春天、江河、田园，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '张志和是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《渔歌子》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、江河、田园”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“西塞山前白鹭飞”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、江河、田园”主题。', annotated_content_json = '[{"char": "西", "pinyin": "xī", "punct": false}, {"char": "塞", "pinyin": "sāi", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "鹭", "pinyin": "lù", "punct": false}, {"char": "飞", "pinyin": "fēi", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "桃", "pinyin": "táo", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "鳜", "pinyin": "guì", "punct": false}, {"char": "鱼", "pinyin": "yú", "punct": false}, {"char": "肥", "pinyin": "féi", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "青", "pinyin": "qīng", "punct": false}, {"char": "箬", "pinyin": "ruò", "punct": false}, {"char": "笠", "pinyin": "lì", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "绿", "pinyin": "lǜ", "punct": false}, {"char": "蓑", "pinyin": "suō", "punct": false}, {"char": "衣", "pinyin": "yī", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "斜", "pinyin": "xié", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "细", "pinyin": "xì", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "须", "pinyin": "xū", "punct": false}, {"char"