UPDATE poems SET pinyin = 'qí wáng zhái lǐ xún cháng jiàn， cuī jiǔ táng qián jǐ dù wén。 zhèng shì jiāng nán hǎo fēng jǐng， luò huā shí jié yòu féng jūn。', translation = '这首《江南逢李龟年》可以先抓住“岐王宅里寻常见”和“落花时节又逢君”这样的画面来理解。诗里写到江南、友情、春天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《江南逢李龟年》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“江南、友情、春天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“岐王宅里寻常见”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“江南、友情、春天”主题。', annotated_content_json = '[{"char": "岐", "pinyin": "qí", "punct": false}, {"char": "王", "pinyin": "wáng", "punct": false}, {"char": "宅", "pinyin": "zhái", "punct": false}, {"char": "里", "pinyin": "lǐ", "punct": false}, {"char": "寻", "pinyin": "xún", "punct": false}, {"char": "常", "pinyin": "cháng", "punct": false}, {"char": "见", "pinyin": "jiàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "崔", "pinyin": "cuī", "punct": false}, {"char": "九", "pinyin": "jiǔ", "punct": false}, {"char": "堂", "pinyin": "táng", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "几", "pinyin": "jǐ", "punct": false}, {"char": "度", "pinyin": "dù", "punct": false}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "正", "pinyin": "zhèng", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "南", "pinyin": "nán", "punct": false}, {"char": "好", "pinyin": "hǎo", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "景", "pinyin": "jǐng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "落", "pinyin": "luò", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "节", "pinyin": "jié", "punct": false}, {"char": "又", "pinyin": "yòu", "punct": false}, {"char": "逢", 