UPDATE poems SET pinyin = 'shù gǔ duàn rén xíng， biān qiū yī yàn shēng。 lù cóng jīn yè bái， yuè shì gù xiāng míng。', translation = '这首《月夜忆舍弟》可以先抓住“戍鼓断人行”和“月是故乡明”这样的画面来理解。诗里写到思乡、亲情、秋天，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《月夜忆舍弟》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“思乡、亲情、秋天”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“戍鼓断人行”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“思乡、亲情、秋天”主题。', annotated_content_json = '[{"char": "戍", "pinyin": "shù", "punct": false}, {"char": "鼓", "pinyin": "gǔ", "punct": false}, {"char": "断", "pinyin": "duàn", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "行", "pinyin": "xíng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "边", "pinyin": "biān", "punct": false}, {"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "雁", "pinyin": "yàn", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "露", "pinyin": "lù", "punct": false}, {"char": "从", "pinyin": "cóng", "punct": false}, {"char": "今", "pinyin": "jīn", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "白", "pinyin": "bái", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "故", "pinyin": "gù", "punct": false}, {"char": "乡", "pinyin": "xiāng", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 156;
UPDATE poems SET pinyin = 'gōng gài sān fēn guó， míng chéng bā zhèn tú。 jiāng liú shí bù zhuǎn， yí hèn shī tūn wú。', translation = '这首《八阵图》可以先抓住“功盖三分国”和“遗恨失吞吴”这样的画面来理解。诗里写到历史、三国、哲理，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《八阵图》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“历史、三国、哲理”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“功盖三分国”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“历史、三国、哲理”主题。', annotated_content_json = '[{"char": "功", "pinyin": "gōng", "punct": false}, {"char": "盖", "pinyin": "gài", "punct": false}, {"char": "三", "pinyin": "sān", "punct": false}, {"char": "分", "pinyin": "fēn", "punct": false}, {"char": "国", "pinyin": "guó", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "名", "pinyin": "míng", "punct": false}, {"char": "成", "pinyin": "chéng", "punct": false}, {"char": "八", "pinyin": "bā", "punct": false}, {"char": "阵", "pinyin": "zhèn", "punct": false}, {"char": "图", "pinyin": "tú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "石", "pinyin": "shí", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "转", "pinyin": "zhuǎn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "遗", "pinyin": "yí", "punct": false}, {"char": "恨", "pinyin": "hèn", "punct": false}, {"char": "失", "pinyin": "shī", "punct": false}, {"char": "吞", "pinyin": "tūn", "punct": false}, {"char": "吴", "pinyin": "wú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 157;
UPDATE poems SET pinyin = 'wǎn gōng dāng wǎn qiáng， yòng jiàn dāng yòng zhǎng。 shè rén xiān shè mǎ， qín zéi xiān qín wáng。', translation = '这首《前出塞》可以先抓住“挽弓当挽强”和“擒贼先擒王”这样的画面来理解。诗里写到边塞、战争、策略，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《前出塞》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“边塞、战争、策略”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“挽弓当挽强”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“边塞、战争、策略”主题。', annotated_content_json = '[{"char": "挽", "pinyin": "wǎn", "punct": false}, {"char": "弓", "pinyin": "gōng", "punct": false}, {"char": "当", "pinyin": "dāng", "punct": false}, {"char": "挽", "pinyin": "wǎn", "punct": false}, {"char": "强", "pinyin": "qiáng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "用", "pinyin": "yòng", "punct": false}, {"char": "箭", "pinyin": "jiàn", "punct": false}, {"char": "当", "pinyin": "dāng", "punct": false}, {"char": "用", "pinyin": "yòng", "punct": false}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "射", "pinyin": "shè", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "先", "pinyin": "xiān", "punct": false}, {"char": "射", "pinyin": "shè", "punct": false}, {"char": "马", "pinyin": "mǎ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "擒", "pinyin": "qín", "punct": false}, {"char": "贼", "pinyin": "zéi", "punct": false}, {"char": "先", "pinyin": "xiān", "punct": false}, {"char": "擒", "pinyin": "qín", "punct": false}, {"char": "王", "pinyin": "wáng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 158;
UPDATE poems SET pinyin = 'jǐn chéng sī guǎn rì fēn fēn， bàn rù jiāng fēng bàn rù yún。 cǐ qū zhǐ yīng tiān shàng yǒu， rén jiān néng dé jǐ huí wén。', translation = '这首《赠花卿》可以先抓住“锦城丝管日纷纷”和“人间能得几回闻”这样的画面来理解。诗里写到音乐、成都、赞美，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《赠花卿》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“音乐、成都、赞美”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“锦城丝管日纷纷”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“音乐、成都、赞美”主题。', annotated_content_json = '[{"char": "锦", "pinyin": "jǐn", "punct": false}, {"char": "城", "pinyin": "chéng", "punct": false}, {"char": "丝", "pinyin": "sī", "punct": false}, {"char": "管", "pinyin": "guǎn", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "纷", "pinyin": "fēn", "punct": false}, {"char": "纷", "pinyin": "fēn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "此", "pinyin": "cǐ", "punct": false}, {"char": "曲", "pinyin": "qū", "punct": false}, {"char": "只", "pinyin": "zhǐ", "punct": false}, {"char": "应", "pinyin": "yīng", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "有", "pinyin": "yǒu", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "间", "pinyin": "jiān", "punct": false}, {"char": "能", "pinyin": "néng", "punct": false}, {"char": "得", "pinyin": "dé", "punct": false}, {"char": "几", "pinyin": "jǐ", "punct": false}, {"char": "回", "pinyin": "huí", 