UPDATE poems SET pinyin = 'qīng jiāng yī qū bào cūn liú， zhǎng xià jiāng cūn shì shì yōu。 zì qù zì lái liáng shàng yàn， xiāng qīn xiāng jìn shuǐ zhōng ōu。', translation = '这首《江村》可以先抓住“清江一曲抱村流”和“相亲相近水中鸥”这样的画面来理解。诗里写到夏天、乡村、江河，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《江村》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“夏天、乡村、江河”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“清江一曲抱村流”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“夏天、乡村、江河”主题。', annotated_content_json = '[{"char": "清", "pinyin": "qīng", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "曲", "pinyin": "qū", "punct": false}, {"char": "抱", "pinyin": "bào", "punct": false}, {"char": "村", "pinyin": "cūn", "punct": false}, {"char": "流", "pinyin": "liú", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "夏", "pinyin": "xià", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "村", "pinyin": "cūn", "punct": false}, {"char": "事", "pinyin": "shì", "punct": false}, {"char": "事", "pinyin": "shì", "punct": false}, {"char": "幽", "pinyin": "yōu", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "自", "pinyin": "zì", "punct": false}, {"char": "去", "pinyin": "qù", "punct": false}, {"char": "自", "pinyin": "zì", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "梁", "pinyin": "liáng", "punct": false}, {"char": "上", "pinyin": "shàng", "punct": false}, {"char": "燕", "pinyin": "yàn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "亲", "pinyin": "qīn", "punct": false}, {"char": "相", "pinyin": "xiāng", "punct": false}, {"char": "近", "pinyin": "jìn", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "中", "pin