UPDATE poems SET pinyin = 'hǎo yǔ zhī shí jié， dāng chūn nǎi fā shēng。 suí fēng qián rù yè， rùn wù xì wú shēng。', translation = '这首《春夜喜雨》可以先抓住“好雨知时节”和“润物细无声”这样的画面来理解。诗里写到春天、雨、自然，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《春夜喜雨》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、雨、自然”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“好雨知时节”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、雨、自然”主题。', annotated_content_json = '[{"char": "好", "pinyin": "hǎo", "punct": false}, {"char": "雨", "pinyin": "yǔ", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "节", "pinyin": "jié", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "当", "pinyin": "dāng", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "乃", "pinyin": "nǎi", "punct": false}, {"char": "发", "pinyin": "fā", "punct": false}, {"char": "生", "pinyin": "shēng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "随", "pinyin": "suí", "punct": false}, {"char": "风", "pinyin": "fēng", "punct": false}, {"char": "潜", "pinyin": "qián", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "润", "pinyin": "rùn", "punct": false}, {"char": "物", "pinyin": "wù", "punct": false}, {"char": "细", "pinyin": "xì", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 161;
UPDATE poems SET pinyin = 'jiàn wài hū chuán shōu jì běi， chū wén tì lèi mǎn yī shang。 què kàn qī zi chóu hé zài， màn juǎn shī shū xǐ yù kuáng。', translation = '这首《闻官军收河南河北》可以先抓住“剑外忽传收蓟北”和“漫卷诗书喜欲狂”这样的画面来理解。诗里写到家国、喜悦、战争，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '杜甫是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《闻官军收河南河北》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“家国、喜悦、战争”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“剑外忽传收蓟北”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“家国、喜悦、战争”主题。', annotated_content_json = '[{"char": "剑", "pinyin": "jiàn", "punct": false}, {"char": "外", "pinyin": "wài", "punct": false}, {"char": "忽", "pinyin": "hū", "punct": false}, {"char": "传", "pinyin": "chuán", "punct": false}, {"char": "收", "pinyin": "shōu", "punct": false}, {"char": "蓟", "pinyin": "jì", "punct": false}, {"char": "北", "pinyin": "běi", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "初", "pinyin": "chū", "punct": false}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "涕", "pinyin": "tì", "punct": false}, {"char": "泪", "pinyin": "lèi", "punct": false}, {"char": "满", "pinyin": "mǎn", "punct": false}, {"char": "衣", "pinyin": "yī", "punct": false}, {"char": "裳", "pinyin": "shang", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "却", "pinyin": "què", "punct": false}, {"char": "看", "pinyin": "kàn", "punct": false}, {"char": "妻", "pinyin": "qī", "punct": false}, {"char": "子", "pinyin": "zi", "punct": false}, {"char": "愁", "pinyin": "chóu", "punct": false}, {"char": "何", "pinyin": "hé", "punct": false}, {"char": "在", "pinyin": "zài", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "漫", "pinyin": "màn", "punct": false}, {"char": "卷", "pinyin": "juǎn", "punct": false}, {"char": "诗", "pinyin": "shī", "punct": false}, {"char": "书", "pinyin": "shū", "punct": false}, {"char": "喜", "pinyin": "xǐ", "punct": false}, {"char": "欲", "pinyin": "yù"