UPDATE poems SET pinyin = 'rén jiān sì yuè fāng fēi jǐn， shān sì táo huā shǐ shèng kāi。 zhǎng hèn chūn guī wú mì chù， bù zhī zhuǎn rù cǐ zhōng lái。', translation = '这首《大林寺桃花》可以先抓住“人间四月芳菲尽”和“不知转入此中来”这样的画面来理解。诗里写到春天、桃花、山寺，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '白居易是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《大林寺桃花》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、桃花、山寺”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“人间四月芳菲尽”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、桃花、山寺”主题。', annotated_content_json = '[{"char": "人", "pinyin": "rén", "punct": false}, {"char": "间", "pinyin": "jiān", "punct": false}, {"char": "四", "pinyin": "sì", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "芳", "pinyin": "fāng", "punct": false}, {"char": "菲", "pinyin": "fēi", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "寺", "pinyin": "sì", "punct": false}, {"char": "桃", "pinyin": "táo", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "始", "pinyin": "shǐ", "punct": false}, {"char": "盛", "pinyin": "shèng", "punct": false}, {"char": "开", "pinyin": "kāi", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "长", "pinyin": "zhǎng", "punct": false}, {"char": "恨", "pinyin": "hèn", "punct": false}, {"char": "春", "pinyin": "chūn", "punct": false}, {"char": "归", "pinyin": "guī", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "觅", "pinyin": "mì", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "知", "pinyin": "zhī", "punct": false}, {"char": "转", "pinyin": "zhuǎn", "punct": false}, {"char": "入", "pinyin": "rù", "punct": false}, {"char": "此", "pinyin": "cǐ", "punct": false}, {"char": "中", "pinyin": "z