UPDATE poems SET pinyin = 'yī dào cán yáng pù shuǐ zhōng， bàn jiāng sè sè bàn jiāng hóng。 kě lián jiǔ yuè chū sān yè， lù shì zhēn zhū yuè shì gōng。', translation = '这首《暮江吟》可以先抓住“一道残阳铺水中”和“露似真珠月似弓”这样的画面来理解。诗里写到秋天、江河、月夜，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '白居易是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《暮江吟》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、江河、月夜”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“一道残阳铺水中”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、江河、月夜”主题。', annotated_content_json = '[{"char": "一", "pinyin": "yī", "punct": false}, {"char": "道", "pinyin": "dào", "punct": false}, {"char": "残", "pinyin": "cán", "punct": false}, {"char": "阳", "pinyin": "yáng", "punct": false}, {"char": "铺", "pinyin": "pù", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "瑟", "pinyin": "sè", "punct": false}, {"char": "瑟", "pinyin": "sè", "punct": false}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "江", "pinyin": "jiāng", "punct": false}, {"char": "红", "pinyin": "hóng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "可", "pinyin": "kě", "punct": false}, {"char": "怜", "pinyin": "lián", "punct": false}, {"char": "九", "pinyin": "jiǔ", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "初", "pinyin": "chū", "punct": false}, {"char": "三", "pinyin": "sān", "punct": false}, {"char": "夜", "pinyin": "yè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "露", "pinyin": "lù", "punct": false}, {"char": "似", "pinyin": "shì", "punct": false}, {"char": "真", "pinyin": "zhēn", "punct": false}, {"char": "珠", "pinyin": "zhū", "punct": false}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "似", "pinyin": "shì"