UPDATE poems SET pinyin = 'gū shān sì běi jiǎ tíng xī， shuǐ miàn chū píng yún jiǎo dī。 jǐ chù zǎo yīng zhēng nuǎn shù， shuí jiā xīn yàn zhuó chūn ní。', translation = '这首《钱塘湖春行》可以先抓住“孤山寺北贾亭西”和“谁家新燕啄春泥”这样的画面来理解。诗里写到春天、西湖、动物，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '白居易是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《钱塘湖春行》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“春天、西湖、动物”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“孤山寺北贾亭西”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“春天、西湖、动物”主题。', annotated_content_json = '[{"char": "孤", "pinyin": "gū", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "寺", "pinyin": "sì", "punct": false}, {"char": "北", "pinyin": "běi", "punct": false}, {"char": "贾", "pinyin": "jiǎ", "punct": false}, {"char": "亭", "pinyin": "tíng", "punct": false}, {"char": "西", "pinyin": "xī", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "面", "pinyin": "miàn", "punct": false}, {"char": "初", "pinyin": "chū", "punct": false}, {"char": "平", "pinyin": "píng", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "脚", "pinyin": "jiǎo", "punct": false}, {"char": "低", "pinyin": "dī", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "几", "pinyin": "jǐ", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "早", "pinyin": "zǎo", "punct": false}, {"char": "莺", "pinyin": "yīng", "punct": false}, {"char": "争", "pinyin": "zhēng", "punct": false}, {"char": "暖", "pinyin": "nuǎn", "punct": false}, {"char": "树", "pinyin": "shù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "谁", "pinyin": "shuí", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "新", "pinyin": "xīn", "punct": false}, {"char": "燕", "pinyin": "yàn", "punct": false}, {"char": "啄", "pinyin": "zhuó", "punct": false}, {"char": "春", "pinyi