UPDATE poems SET pinyin = 'lǜ yǐ xīn pēi jiǔ， hóng ní xiǎo huǒ lú。 wǎn lái tiān yù xuě， néng yǐn yī bēi wú。', translation = '这首《问刘十九》可以先抓住“绿蚁新醅酒”和“能饮一杯无”这样的画面来理解。诗里写到冬天、友情、生活，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '白居易是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《问刘十九》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“冬天、友情、生活”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“绿蚁新醅酒”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“冬天、友情、生活”主题。', annotated_content_json = '[{"char": "绿", "pinyin": "lǜ", "punct": false}, {"char": "蚁", "pinyin": "yǐ", "punct": false}, {"char": "新", "pinyin": "xīn", "punct": false}, {"char": "醅", "pinyin": "pēi", "punct": false}, {"char": "酒", "pinyin": "jiǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "红", "pinyin": "hóng", "punct": false}, {"char": "泥", "pinyin": "ní", "punct": false}, {"char": "小", "pinyin": "xiǎo", "punct": false}, {"char": "火", "pinyin": "huǒ", "punct": false}, {"char": "炉", "pinyin": "lú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "晚", "pinyin": "wǎn", "punct": false}, {"char": "来", "pinyin": "lái", "punct": false}, {"char": "天", "pinyin": "tiān", "punct": false}, {"char": "欲", "pinyin": "yù", "punct": false}, {"char": "雪", "pinyin": "xuě", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "能", "pinyin": "néng", "punct": false}, {"char": "饮", "pinyin": "yǐn", "punct": false}, {"char": "一", "pinyin": "yī", "punct": false}, {"char": "杯", "pinyin": "bēi", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 167;
UPDATE poems SET pinyin = 'nòng shí lín xī zuò， xún huā rào sì xíng。 shí shí wén niǎo yǔ， chù chù shì quán shēng。', translation = '这首《遗爱寺》可以先抓住“弄石临溪坐”和“处处是泉声”这样的画面来理解。诗里写到山水、花鸟、闲适，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '白居易是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《遗爱寺》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“山水、花鸟、闲适”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“弄石临溪坐”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“山水、花鸟、闲适”主题。', annotated_content_json = '[{"char": "弄", "pinyin": "nòng", "punct": false}, {"char": "石", "pinyin": "shí", "punct": false}, {"char": "临", "pinyin": "lín", "punct": false}, {"char": "溪", "pinyin": "xī", "punct": false}, {"char": "坐", "pinyin": "zuò", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "寻", "pinyin": "xún", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "绕", "pinyin": "rào", "punct": false}, {"char": "寺", "pinyin": "sì", "punct": false}, {"char": "行", "pinyin": "xíng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "时", "pinyin": "shí", "punct": false}, {"char": "闻", "pinyin": "wén", "punct": false}, {"char": "鸟", "pinyin": "niǎo", "punct": false}, {"char": "语", "pinyin": "yǔ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "处", "pinyin": "chù", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "泉", "pinyin": "quán", "punct": false}, {"char": "声", "pinyin": "shēng", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 168;
UPDATE poems SET pinyin = 'shuāng cǎo cāng cāng chóng qiè qiè， cūn nán cūn běi xíng rén jué。 dú chū mén qián wàng yě tián， yuè míng qiáo mài huā rú xuě。', translation = '这首《村夜》可以先抓住“霜草苍苍虫切切”和“月明荞麦花如雪”这样的画面来理解。诗里写到秋天、月夜、乡村，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '白居易是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《村夜》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、月夜、乡村”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“霜草苍苍虫切切”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、月夜、乡村”主题。', annotated_content_json = '[{"char": "霜", "pinyin": "shuāng", "punct": false}, {"char": "草", "pinyin": "cǎo", "punct": false}, {"char": "苍", "pinyin": "cāng", "punct": false}, {"char": "苍", "pinyin": "cāng", "punct": false}, {"char": "虫", "pinyin": "chóng", "punct": false}, {"char": "切", "pinyin": "qiè", "punct": false}, {"char": "切", "pinyin": "qiè", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "村", "pinyin": "cūn", "punct": false}, {"char": "南", "pinyin": "nán", "punct": false}, {"char": "村", "pinyin": "cūn", "punct": false}, {"char": "北", "pinyin": "běi", "punct": false}, {"char": "行", "pinyin": "xíng", "punct": false}, {"char": "人", "pinyin": "rén", "punct": false}, {"char": "绝", "pinyin": "jué", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "独", "pinyin": "dú", "punct": false}, {"char": "出", "pinyin": "chū", "punct": false}, {"char": "门", "pinyin": "mén", "punct": false}, {"char": "前", "pinyin": "qián", "punct": false}, {"char": "望", "pinyin": "wàng", "punct": false}, {"char": "野", "pinyin": "yě", "punct": false}, {"char": "田", "pinyin": "tián", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "月", "pinyin": "yuè", "punct": false}, {"char": "明", "pinyin": "míng", "punct": false}, {"char": "荞", "pinyin": "qiáo", "punct": false}, {"char": "麦", "pinyin": "mài", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "如", "piny