UPDATE poems SET pinyin = 'qiū cóng rào shě shì táo jiā， biàn rào lí biān rì jiàn xié。 bù shì huā zhōng piān ài jú， cǐ huā kāi jǐn gèng wú huā。', translation = '这首《菊花》可以先抓住“秋丛绕舍似陶家”和“此花开尽更无花”这样的画面来理解。诗里写到秋天、菊花、品格，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '元稹是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《菊花》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“秋天、菊花、品格”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“秋丛绕舍似陶家”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“秋天、菊花、品格”主题。', annotated_content_json = '[{"char": "秋", "pinyin": "qiū", "punct": false}, {"char": "丛", "pinyin": "cóng", "punct": false}, {"char": "绕", "pinyin": "rào", "punct": false}, {"char": "舍", "pinyin": "shě", "punct": false}, {"char": "似", "pinyin": "shì", "punct": false}, {"char": "陶", "pinyin": "táo", "punct": false}, {"char": "家", "pinyin": "jiā", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "遍", "pinyin": "biàn", "punct": false}, {"char": "绕", "pinyin": "rào", "punct": false}, {"char": "篱", "pinyin": "lí", "punct": false}, {"char": "边", "pinyin": "biān", "punct": false}, {"char": "日", "pinyin": "rì", "punct": false}, {"char": "渐", "pinyin": "jiàn", "punct": false}, {"char": "斜", "pinyin": "xié", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "中", "pinyin": "zhōng", "punct": false}, {"char": "偏", "pinyin": "piān", "punct": false}, {"char": "爱", "pinyin": "ài", "punct": false}, {"char": "菊", "pinyin": "jú", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "此", "pinyin": "cǐ", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "开", "pinyin": "kāi", "punct": false}, {"char": "尽", "pinyin": "jǐn", "punct": false}, {"char": "更", "pinyin": "gèng", "punct": false}, {"char": "无", "pinyin": "wú", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "。", "pinyin": "", "punct": true}]' WHERE id = 170;
UPDATE poems SET pinyin = 'céng jīng cāng hǎi nán wèi shuǐ， chú què wū shān bù shì yún。 qǔ cì huā cóng lǎn huí gù， bàn yuán xiū dào bàn yuán jūn。', translation = '这首《离思》可以先抓住“曾经沧海难为水”和“半缘修道半缘君”这样的画面来理解。诗里写到情感、人生、哲理，有的是自然景色，有的是离别思念，有的是勤学劳动或人生道理。给孩子讲时，不必逐字硬翻译，可以先把每一句变成一个小画面，再连起来体会诗人的心情。', story = '元稹是唐代诗人。这首诗篇幅不长，但画面感很强。孩子读《离思》时，可以想象诗人看到的景物、听到的声音，或者当时正在经历的事情。如果诗中有“情感、人生、哲理”这样的主题，就可以联系生活：什么时候见过类似的景色？有没有相似的心情？', parent_guide = '亲子讲解建议：先让孩子听一遍，再一起找出最有画面感的一句，比如“曾经沧海难为水”。然后问三个小问题：这首诗写了什么地方？诗人可能是什么心情？你最喜欢哪个字或哪一句？最后可以让孩子用自己的话复述一遍，再试着背前两句。适合归入“情感、人生、哲理”主题。', annotated_content_json = '[{"char": "曾", "pinyin": "céng", "punct": false}, {"char": "经", "pinyin": "jīng", "punct": false}, {"char": "沧", "pinyin": "cāng", "punct": false}, {"char": "海", "pinyin": "hǎi", "punct": false}, {"char": "难", "pinyin": "nán", "punct": false}, {"char": "为", "pinyin": "wèi", "punct": false}, {"char": "水", "pinyin": "shuǐ", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "除", "pinyin": "chú", "punct": false}, {"char": "却", "pinyin": "què", "punct": false}, {"char": "巫", "pinyin": "wū", "punct": false}, {"char": "山", "pinyin": "shān", "punct": false}, {"char": "不", "pinyin": "bù", "punct": false}, {"char": "是", "pinyin": "shì", "punct": false}, {"char": "云", "pinyin": "yún", "punct": false}, {"char": "。", "pinyin": "", "punct": true}, {"char": "取", "pinyin": "qǔ", "punct": false}, {"char": "次", "pinyin": "cì", "punct": false}, {"char": "花", "pinyin": "huā", "punct": false}, {"char": "丛", "pinyin": "cóng", "punct": false}, {"char": "懒", "pinyin": "lǎn", "punct": false}, {"char": "回", "pinyin": "huí", "punct": false}, {"char": "顾", "pinyin": "gù", "punct": false}, {"char": "，", "pinyin": "", "punct": true}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "缘", "pinyin": "yuán", "punct": false}, {"char": "修", "pinyin": "xiū", "punct": false}, {"char": "道", "pinyin": "dào", "punct": false}, {"char": "半", "pinyin": "bàn", "punct": false}, {"char": "缘", "pinyin": "yuán", "pun